hooks.command:
node -e "
const fs = require('fs');
const path = require('path');
try {
  const input = JSON.parse(require('fs').readFileSync(0, 'utf-8'));
  const filePath = input.tool_input?.file_path || input.tool_response?.filePath || '';

  if (!filePath) process.exit(0);
  if (!filePath.includes('Lovie_task.md')) process.exit(0);

  if (!fs.existsSync(filePath)) {
    console.log(JSON.stringify({systemMessage: '⚠️ Lovie_task.md okunmadı'}));
    process.exit(0);
  }

  const requirements = [
    'Request Creation Flow',
    'Request Management Dashboard',
    'Request Detail View',
    'Payment Fulfillment Simulation',
    'Request Expiration',
    'Authentication',
    'Data Persistence',
    'Responsive Design',
    'Deployment',
    'E2E Tests'
  ];

  const content = fs.readFileSync(filePath, 'utf-8');
  const missing = requirements.filter(req => !content.includes(req));

  if (missing.length > 0) {
    console.log(JSON.stringify({systemMessage: '⚠️ Lovie_task.md eksik: ' + missing.join(', ')}));
  } else {
    console.log(JSON.stringify({systemMessage: '✅ Lovie_task.md: Tüm requirements var'}));
  }
} catch(e) {}
" 2>/dev/null || true
